Agent SQL:
SELECT id, name, country, client_company_name, time_zone, city, start_date, description
FROM projects
WHERE country = 'France';

SELECT id, name, country, client_company_name, time_zone, city, start_date, description
FROM projects
WHERE city = 'Toulouse';

SELECT id, name, country, client_company_name, time_zone, city, start_date, description
FROM projects
WHERE client_company_name = 'LIGAM';

SELECT start_date
FROM projects
WHERE name = 'M3-GC03 TISSEO';

SELECT id, name, country, client_company_name, time_zone, city, start_date, description
FROM projects
WHERE time_zone = 'Europe/Paris';

SELECT id, name
FROM projects
ORDER BY name;

SELECT id, name, country, client_company_name, time_zone, city, start_date, description
FROM projects
WHERE city = 'Paris';

SELECT id_1, name_2, type, extent, start_date_3, previsional_end, project_id, created_at, updated_at, deleted, operating_rate, main_site
FROM sites
WHERE type = 'OTHERS';

SELECT previsional_end
FROM sites
WHERE name_2 = 'MAT_Avoisinants';

SELECT id_1, name_2, type, project_id, operating_rate
FROM sites
ORDER BY operating_rate DESC;

SELECT start_date_3
FROM sites
WHERE id_1 = 1085;

SELECT id_1, name_2, type, extent, start_date_3, previsional_end, project_id, created_at, updated_at, deleted, operating_rate, main_site
FROM sites
WHERE created_at > '2023-05-01';

SELECT id, gateway_name, serial_number, transfer_protocol, power_supply, installation_date, operating_team, x, y, z, time_zone, geom, created_at, updated_at, provider, site_id
FROM gateways
WHERE power_supply = 'Main Supply';

SELECT id, gateway_name, serial_number, transfer_protocol, power_supply, installation_date, operating_team, x, y, z, time_zone, geom, created_at, updated_at, provider, site_id
FROM gateways
WHERE site_id = 1085;

SELECT id, gateway_name, serial_number, transfer_protocol, power_supply, installation_date, operating_team, x, y, z, time_zone, geom, created_at, updated_at, provider, site_id
FROM gateways
WHERE time_zone = 'Europe/Paris';

SELECT DISTINCT power_supply
FROM gateways
WHERE power_supply IS NOT NULL;

SELECT DISTINCT file_name
FROM configs
WHERE file_name IS NOT NULL;

SELECT id_1, file_name, ftp_ip, gateway_id, error_message, last_treatment, updated_at_1
FROM configs
WHERE error_message IS NOT NULL AND error_message != 'None';

SELECT last_treatment
FROM configs
WHERE id_1 = 5419;

SELECT variable_id, value, sensor_id, timestamp, unit, gateway_name, metric, variable_name, variable_alias
FROM variables_metrics_raw_data
WHERE variable_name = 'AccelerationZ';

SELECT DISTINCT variable_alias
FROM variables_metrics_raw_data
ORDER BY variable_alias;

SELECT *
FROM variables_metrics_raw_data
WHERE sensor_id = 15912;

SELECT *
FROM variables_metrics_raw_data
WHERE timestamp::date BETWEEN '2024-11-20' AND '2024-11-22';

SELECT s.name_2, p.name
FROM sites s
LEFT JOIN projects p ON s.project_id = p.id;

SELECT g.gateway_name, s.name_2
FROM gateways g
JOIN sites s ON g.site_id = s.id_1;

SELECT c.file_name, g.gateway_name
FROM configs c
JOIN gateways g ON c.gateway_id = g.id;
